"use strict";parserFactory.register("mcstories.com",()=>new McStoriesParser);class McStoriesParser extends Parser{constructor(){super()}getChapterUrls(e){let r=e.querySelector("table#index, div.chapter");return Promise.resolve(util.hyperlinksToChapterList(r))}findContent(e){return e.querySelector("article")}extractAuthor(e){let r=e.querySelector("article a[href*='/Authors/']");return null===r?super.extractAuthor(e):r.textContent}getInformationEpubItemChildNodes(e){return[util.dctermsToTable(e)]}}